using UnityEngine;

public enum MovementMode
{
    Land,
    SwimOnly
}

public enum SizeCategory
{
    Small,
    Medium,
    Large
}

public enum WeightCategory
{
    Light,
    Normal,
    Heavy
}

public enum SwimType
{
    None,
    Surface,
    Underwater
}

public enum PrimaryAbility
{
    None,
    Dash,
    Sprint,
    Glide,

    /// <summary>OBSOLETO no botão de habilidade: escalar passou para o botão de AGARRAR + cima (ver ClimbAbility/ClimbableSurface). Mantido para não partir assets antigos.</summary>
    [System.Obsolete("Climb deixou de ser PrimaryAbility: a escalada é contextual (categoria Escalador + superfície escalável + Interagir/agarrar + direcção cima/baixo). Não atribuir este valor a novos AnimalFormData; AbilityRouter já o ignora (cai no 'default').")]
    Climb,

    Charge,
    Roll,
    Camo,
    Sonar,
    TonguePull,
    Egg,

    /// <summary>Golpe pesado como habilidade (ex: Urso Polar — ataque normal = garras; habilidade = golpe pesado que quebra gelo/objectos).</summary>
    HeavyStrike,

    /// <summary>Rugido que atordoa inimigos próximos (Leão/Tigre).</summary>
    Roar,

    /// <summary>Postura de escudo (Tartaruga Marinha — reduz dano enquanto seguro).</summary>
    ShellGuard,

    /// <summary>Visão nocturna (P8 — Coruja H2, hasVision): toggle que revela NightVisionRevealable num raio.</summary>
    NightVision,

    /// <summary>Tarefa #7 — Onça-pintada: salto ofensivo que impulsiona o corpo automaticamente contra o inimigo mais próximo (dano "de borla" via PlayerAttack.damageWhileDashing, tal como Charge).</summary>
    Pounce,

    /// <summary>Tarefa #7 — Diabo-da-Tasmânia: rodopio ofensivo, causa dano em área a intervalos enquanto gira no lugar.</summary>
    SpinAttack,

    /// <summary>Tarefa #7 — Pinguim: travagem/curva instantânea, só tem efeito em cima de gelo (PlayerMotor2D.IsOnIce).</summary>
    IceBrake
}

[System.Flags]
public enum AnimalCategory
{
    None       = 0,
    Rapido     = 1 << 0,
    Saltador   = 1 << 1,
    Escalador  = 1 << 2,
    Forte      = 1 << 3,
    Predador   = 1 << 4,
    Voador     = 1 << 5,
    Aquatico   = 1 << 6,
    Furtivo    = 1 << 7,

    /// <summary>Usado principalmente pelo sistema de fraquezas de inimigos (Enemy Creator) — "fraco contra Resistente".</summary>
    Resistente = 1 << 8,

    // Categorias secundárias das fichas do GDD (cap. 7) — P1:
    /// <summary>Coruja — visão nocturna/realce.</summary>
    Percepcao  = 1 << 9,

    /// <summary>Babuíno/Sapo — puxar/arremessar/manipular objectos.</summary>
    Manipulador = 1 << 10,

    /// <summary>Texugo — escava terra macia/túneis.</summary>
    Escavador  = 1 << 11,

    /// <summary>Leão/Wombat/Tigre — animal secreto.</summary>
    Secreto    = 1 << 12,

    /// <summary>Garça — pouso/planagem de precisão.</summary>
    Precisao   = 1 << 13
}

/// <summary>
/// Força de empurrão de blocos de uma forma (fichas do GDD: "Pode empurrar
/// blocos?" — Não/Leves/Médios/Pesados/Grandes). Consumido por PushableBlock.
/// Cada nível inclui os anteriores (Grandes empurra tudo).
/// </summary>
public enum PushStrength
{
    Nao = 0,
    Leves = 1,
    Medios = 2,
    Pesados = 3,
    Grandes = 4
}

/// <summary>
/// Acesso a fendas/túneis de uma forma (fichas do GDD: "Pode entrar em
/// fendas?" — muito baixas/baixas/médias/tocas e túneis). Cada nível inclui os
/// menores (quem entra em Médias entra em Baixas e MuitoBaixas). Túneis
/// (escavar) é à parte — ver "canTunnel"/categoria Escavador.
/// </summary>
public enum CrevasseAccess
{
    Nenhuma = 0,
    MuitoBaixas = 1,
    Baixas = 2,
    Medias = 3
}


[CreateAssetMenu(menuName = "Animals/Animal Form Data", fileName = "NewAnimalForm")]
public class AnimalFormData : ScriptableObject
{
    [Header("Identity")]
    public string formId = "horse";
    public string displayName = "Cavalo";

    [Tooltip("Ícone pequeno usado no cabeçalho do Menu de Pausa (animal actualmente equipado) e noutros locais de UI.")]
    public Sprite icon;

    [Header("Sequência \"Novo Animal Desbloqueado\" (Tarefa #8)")]
    [Tooltip("Ilustração grande (opcional) mostrada no banner de desbloqueio (NewAnimalUnlockedUI). Se vazio, usa 'icon'.")]
    public Sprite unlockArtwork;

    [Tooltip("Música/sting tocado (AudioManager.PlaySE) quando esta forma é desbloqueada pela primeira vez (PlayerProgress.AnimalUnlocked). Se vazio, usa o som padrão de NewAnimalUnlockedUI.")]
    public AudioClip unlockFanfare;

    [Tooltip("Nome do trigger do Animator do player disparado (SetTrigger) ao desbloquear esta forma — animação de celebração curta (opcional, vazio = nenhuma).")]
    public string unlockCelebrationTrigger = "";

    [Header("Primary Ability (Ability Button)")]
    public PrimaryAbility primaryAbility = PrimaryAbility.None;

    [Header("Categories")]
    public SizeCategory size = SizeCategory.Medium;
    public WeightCategory weight = WeightCategory.Normal;

    [Header("Categoria(s) - GDD")]
    [Tooltip("Categorias do GDD usadas pelas condições do sistema de NPC (ex: \"Player transformado em categoria X\"). Pode combinar mais que uma.")]
    public AnimalCategory categories = AnimalCategory.None;

    [Tooltip("Opcional: valor num�rico de peso (para placas/empurr�o/queda). 1 = normal.")]
    public float weightMultiplier = 1.0f;

    [Header("Combate (fichas GDD: Dano/Defesa 1-10) — P1")]
    [Tooltip("Esta forma ataca? Nem todos os animais atacam (decisão de design: uns são de combate, outros de puzzle). Ex: Coruja/Sapo/Garça = não; Raposa = ataque básico fraco; Leão/Tigre = golpe pesado.")]
    public bool canAttack = true;

    [Tooltip("Dano de ataque da forma (fichas: 1-10; ex: Leão 9, Tigre 10, Coruja 1). Usado por PlayerAttack → EnemyHealth.TakeDamage (com fraquezas por categoria).")]
    [Range(1, 10)] public int attackDamage = 3;

    [Tooltip("Defesa da forma (fichas: 1-10). Reduz dano recebido por patamares: 1-4 sem redução; 5-7 reduz 1 em ataques de 2+; 8-10 reduz 1 sempre (mínimo 1). Ver ApplyDefense.")]
    [Range(1, 10)] public int defense = 3;

    [Tooltip("Tarefa #28 — Multiplicador aplicado ao knockback (empurrão) recebido pelo player nesta forma (1 = normal, sem redução). Formas da categoria 'Resistente' devem usar um valor menor (ex: 0.5) para resistência passiva a knockback.")]
    [Range(0f, 1f)] public float knockbackResistance = 1f;

    [Tooltip("Alcance do ataque básico (hitbox frontal), em metros.")]
    public float attackRange = 1.2f;

    [Tooltip("Força de knockback aplicada aos inimigos atingidos pelo ataque básico.")]
    public float attackKnockback = 5f;

    [Tooltip("Tempo mínimo entre ataques básicos (segundos).")]
    public float attackCooldown = 0.5f;

    [Header("Empurrar Blocos (fichas GDD) — P1")]
    [Tooltip("Força de empurrão em terra (Não/Leves/Médios/Pesados/Grandes). Substitui o antigo 'canPush' (mantido por compatibilidade). Consumido por PushableBlock.")]
    public PushStrength pushStrength = PushStrength.Nao;

    [Tooltip("Força de empurrão DENTRO de água (ex: Polvo/Tartaruga: 'médios só em água'). Usa o maior dos dois quando em água.")]
    public PushStrength pushStrengthInWater = PushStrength.Nao;

    [Header("Fendas (fichas GDD) — P1")]
    [Tooltip("Tamanho de fendas em que esta forma entra (cada nível inclui os menores). Consumido pelas zonas de fenda/CrawlAbility. Túneis escaváveis são via 'canTunnel'.")]
    public CrevasseAccess crevasseAccess = CrevasseAccess.Nenhuma;

    [Header("Movement Mode")]
    public MovementMode movementMode = MovementMode.Land;

    [Header("Water")]
    public SwimType swimType = SwimType.None;

    [Tooltip("Velocidade base na �gua (para o futuro WaterMotor).")]
    public float swimSpeed = 6f;

    [Tooltip("Animal anfíbio/híbrido (GDD 4.1, \"Regra de animais anfíbios ou híbridos\"): mesmo sendo aquático (movementMode == SwimOnly ou swimType != None), esta forma também pode ser seleccionada em terra. Ex: Polvo (Aquático/Escalador) — \"Pode actuar em terra?\" = Sim. \"Pode mergulhar?\"/\"Pode transformar submerso?\" continuam representados por swimType == Underwater.")]
    public bool canActOnLand = false;

    [Header("Oxigênio Subaquático (animais terrestres que mergulham)")]
    [Tooltip("Marca este animal TERRESTRE como capaz de mergulhar (ex: Texugo, Wombat). Diferente de swimType == Underwater: este animal NÃO é aquático por natureza — tem oxigênio limitado debaixo de água e morre ao ficar sem ar. Ignorado se swimType == Underwater (animais aquáticos nativos não usam o sistema de oxigênio).")]
    public bool canDiveAsLand = false;

    [Tooltip("Oxigênio máximo (segundos de fôlego) quando este animal mergulha. Ao recolher uma Bolha de Ar, restaura para este valor. Ex: Texugo = 8, Wombat = 5.")]
    [Min(1f)] public float maxOxygen = 8f;

    [Tooltip("Taxa de consumo de oxigênio por segundo enquanto submerso (sem input de subida). Ex: 1.0 = usa 1 segundo de oxigênio por segundo real.")]
    [Min(0.1f)] public float oxygenDrainRate = 1f;

    [Header("Water Motor Stats (Tarefa #14 — WaterMotor2D)")]
    [Tooltip("Aceleração horizontal/vertical (m/s²) ao nadar com input. Quanto maior, mais responsiva a natação.")]
    public float swimAccel = 14f;

    [Tooltip("Desaceleração (m/s²) ao nadar sem input (resistência da água ao parar de remar).")]
    public float swimDecel = 8f;

    [Tooltip("Multiplicador aplicado a 'swimSpeed' para o movimento vertical (mergulho/subida). 1 = igual ao horizontal. Formas 'Surface' (não mergulham activamente) podem usar valores baixos.")]
    [Range(0f, 2f)] public float verticalSwimMultiplier = 1f;

    [Tooltip("GravityScale do Rigidbody2D enquanto esta forma está dentro de água (IsActive do WaterMotor2D). 0 = flutuação neutra (recomendado para a maioria das formas aquáticas).")]
    public float underwaterGravityScale = 0f;

    [Tooltip("Rigidbody2D.drag aplicado dentro de água (resistência da água). Restaurado ao valor original ao saír da água.")]
    public float waterDrag = 1.5f;

    [Tooltip("Apenas para swimType == Surface: velocidade (m/s) com que a forma sobe de volta à superfície se for arrastada para debaixo de água (ex.: por uma corrente). 0 = desactivado.")]
    public float surfaceFloatSpeed = 3f;

    [Header("Flutuação (animais terrestres — swimType == None)")]
    [Tooltip("Se activo, este animal terrestre flutua na superfície da água em vez de afundar (ex: qualquer animal padrão). O WaterMotor2D aplica gravidade reduzida + força de subida ao estar submerso. Deixar false em animais que afundam propositalmente (ex: animais pesados).")]
    public bool floatsOnWaterSurface = false;

    [Tooltip("GravityScale aplicado ao Rigidbody2D quando este animal (não-nadador com floatsOnWaterSurface = true) está dentro de água. Valores próximos de 0 criam flutuação neutra; valores negativos fazem o animal subir activamente. Padrão: 0.15 (cai muito devagar, sobe sozinho).")]
    public float nonSwimmerWaterGravityScale = 0.15f;

    [Tooltip("Velocidade (m/s) com que o animal sobe à superfície quando submerso (floatsOnWaterSurface = true). Semelhante a surfaceFloatSpeed, mas para não-nadadores. 0 = desactivado (usa apenas a gravidade reduzida).")]
    public float nonSwimmerFloatSpeed = 4f;

    [Header("Afogamento (swimType == None && floatsOnWaterSurface == false)")]
    [Tooltip("⚠ OBRIGATÓRIO preencher 'waterWarningText' se este campo for > 0:\nSegundos submerso até o player morrer afogado. 0 = morte imediata ao tocar a água. Padrão: 0.8s (dá breve feedback antes de matar).")]
    [Min(0f)] public float sinkingDeathDelay = 0.8f;

    [Tooltip("⚠ OBRIGATÓRIO se floatsOnWaterSurface = false e swimType = None:\nMensagem de tutorial ('Média') mostrada UMA ÚNICA VEZ quando o player entra em água com esta forma. Deve deixar claro que o animal não sabe nadar (ex: 'O Leão não sabe nadar! Mantém-te longe da água.'). SEM este aviso, o jogador morre sem perceber porquê.")]
    [TextArea(2, 4)] public string waterWarningText = "";

    [Tooltip("Força do 'impulso aquático' (kick), aplicada na direcção do movimento (ou para a frente/cima, sem input) ao premir Saltar dentro de água.")]
    public float aquaticImpulseForce = 7f;

    [Tooltip("Tempo de recarga (segundos) entre impulsos aquáticos.")]
    public float aquaticImpulseCooldown = 0.6f;

    [Tooltip("Aderência do Polvo (GDD): segurando Interagir junto a uma superfície dentro de água, fica agarrado e imóvel (sem gravidade/corrente). Usa 'wallLayer' do WaterMotor2D para detectar superfícies.")]
    public bool canClingUnderwater = false;

    [Tooltip("Tarefa #7 — Tartaruga: resistência própria a correntes de água (0 = nenhuma, 1 = imune), independente da Bolha de Coral (item — imunidade temporária). A força da corrente é multiplicada por (1 - currentResistance) em WaterMotor2D.AddCurrentForce.")]
    [Range(0f, 1f)] public float currentResistance = 0f;

    [Header("Physics")]
    [Tooltip("GravityScale aplicado ao Rigidbody2D quando esta forma � activada. (1 = padr�o)")]
    public float gravityScale = 1.0f;

    [Header("Collider (Capsule)")]
    public Vector2 colliderSize = new Vector2(0.8f, 1.4f);
    public Vector2 colliderOffset = new Vector2(0f, -0.1f);

    [Header("Ground Check Override (optional)")]
    public bool overrideGroundCheck = false;
    public Vector2 groundCheckOffset = new Vector2(0f, -0.65f);
    public Vector2 groundCheckSize = new Vector2(0.45f, 0.12f);

    [Header("Run / Feel")]
    public float baseSpeed = 7.0f;
    public float maxSpeed = 10.0f;
    public float timeToMaxSpeed = 1.2f;

    public float accel = 120f;
    public float decel = 35f;

    [Header("Turn / Skid (Mario-like)")]
    public float turnLockSpeed = 6.0f;
    public float skidBrake = 55f;

    [Header("Gelo (P8 — Pinguim)")]
    [Tooltip("Em terreno marcado como 'gelo' (PlayerMotor2D.iceLayer), multiplica accel/decel/skidBrake desta forma. 1 = sem efeito (agarra normalmente mesmo no gelo — a maioria dos animais). Valores baixos (ex: Pinguim ~0.08) fazem a forma deslizar muito, quase sem atrito, preservando o momentum.")]
    [Range(0.05f, 1f)] public float iceSlideFactor = 1f;

    [Header("Vento (Tarefa #7 — Guepardo)")]
    [Tooltip("Sprint extremo do Guepardo: enquanto SprintAbility.IsSprinting, ignora WindZones marcadas como 'isSmallCurrent' (correntes fracas) — \"quebra\" pequenas correntes de vento ao correr. Ver PlayerMotor2D.ApplyWind.")]
    public bool canBreakSmallWindCurrents = false;

    [Header("Jump")]
    public bool canJump = true;
    public float jumpForce = 14.0f;
    [Range(0.1f, 1f)] public float jumpCutMultiplier = 0.45f;
    public int extraJumps = 0;
    public float coyoteTime = 0.10f;
    public float jumpBuffer = 0.10f;

    [Header("Abilities (flags)")]
    public bool canDash = false;

    public bool canGlide = false;
    public bool canClimb = false;
    public bool canCrawl = false;
    public bool canTunnel = false;     // TNL (buracos/t�neis)
    public bool canCharge = false;     // CHG
    public bool canRoll = false;       // ROL

    [Header("Interaction (flags)")]
    public bool canPush = false;

    [Tooltip("Pode PUXAR um PushableBlock (segurar Interagir junto ao bloco e andar para trás — mais lento que empurrar). Independente de pushStrength: empurrar é por toque, puxar precisa desta flag.")]
    public bool canPull = false;

    public bool canGrab = false;
    public bool canThrow = false;
    public bool canPullToSelf = false; // l�ngua / puxar argolas

    public bool canBreakWood = false;  // BRK-W
    public bool canBreakBig = false;   // BRK-B
    public bool canBreakIce = false;   // BRK-I (podes tamb�m usar weight Heavy)

    [Header("Senses / Stealth")]
    public bool isStealthy = false;    // reduz detec��o passiva
    public bool canCamo = false;       // camuflagem activa
    public bool hasVision = false;     // VISION
    public bool hasSonar = false;      // SONAR

    [Header("Dash Stats (optional)")]
    public float dashSpeed = 16f;
    public float dashDuration = 0.18f;
    public float dashCooldown = 0.45f;
    public float dashGravityScale = 0.5f;

    [Header("Charge Stats (optional) — investida em terra (CHG)")]
    [Tooltip("Velocidade da investida em terra (m/s). A investida aquática (Orca) continua a usar dashSpeed/dashDuration.")]
    public float chargeSpeed = 14f;

    [Tooltip("Duração da investida em terra (segundos).")]
    public float chargeDuration = 0.3f;

    [Tooltip("Tempo de recarga (segundos) entre investidas em terra.")]
    public float chargeCooldown = 1.2f;

    [Header("Roll Stats (optional) — rolamento (ROL)")]
    [Tooltip("Velocidade do rolamento (m/s).")]
    public float rollSpeed = 12f;

    [Tooltip("Duração do rolamento (segundos).")]
    public float rollDuration = 0.4f;

    [Tooltip("Tempo de recarga (segundos) entre rolamentos.")]
    public float rollCooldown = 0.8f;

    [Tooltip("Bónus de Defesa (somado à tabela 1-10 de 'defense') enquanto a rolar — ver ApplyRollDefense em RollAbility.")]
    [Range(0, 10)] public int rollDefenseBonus = 3;

    [Tooltip("Força do empurrão aplicado a inimigos atingidos durante o rolamento.")]
    public float rollPushForce = 8f;

    [Tooltip("Raio (m) à frente do player onde o rolamento detecta inimigos para empurrar.")]
    public float rollPushRadius = 0.9f;

    [Header("Glide Stats (optional)")]
    [Tooltip("GravityScale aplicado ao Rigidbody2D enquanto o player está a planar (GLD). Deve ser menor que 'gravityScale' normal para criar a queda lenta.")]
    public float glideGravityScale = 0.25f;

    [Tooltip("Velocidade máxima de queda (m/s, valor positivo) enquanto está a planar. A velocidade vertical é limitada a -glideFallSpeed.")]
    public float glideFallSpeed = 2.5f;

    [Header("Climb Stats (optional)")]
    [Tooltip("Velocidade de subida/descida (m/s) enquanto o player está agarrado a uma superfície escalável (CLM).")]
    public float climbSpeed = 4f;

    [Tooltip("Tarefa #7 — Coala: bónus de Defesa (somado à tabela 1-10 de 'defense') enquanto agarrado/a escalar (ClimbAbility.IsClimbing). Ver ClimbAbility.ApplyClimbDefense — mesmo padrão de rollDefenseBonus.")]
    [Range(0, 10)] public int climbDefenseBonus = 0;

    [Header("Crawl Stats (optional)")]
    [Tooltip("Tamanho do CapsuleCollider2D usado enquanto o player está a rastejar (CRW), para passar por espaços baixos.")]
    public Vector2 crawlColliderSize = new Vector2(0.8f, 0.7f);

    [Tooltip("Offset do CapsuleCollider2D usado enquanto o player está a rastejar (CRW).")]
    public Vector2 crawlColliderOffset = new Vector2(0f, -0.45f);

    [Tooltip("Multiplicador aplicado à velocidade horizontal (baseSpeed/maxSpeed) enquanto está a rastejar. 1 = sem alteração.")]
    [Range(0.1f, 1f)] public float crawlSpeedMultiplier = 0.5f;

    [Header("Sprint Stats (optional)")]
    [Tooltip("Multiplicador de velocidade (baseSpeed/maxSpeed) enquanto o botão de habilidade está seguro (SprintAbility). 1 = sem efeito.")]
    public float sprintSpeedMultiplier = 1.5f;

    [Header("Camo Stats (optional)")]
    [Tooltip("Duração da camuflagem (segundos) — durante este tempo o player conta como Furtivo para EnemyDetection.")]
    public float camoDuration = 4f;

    [Tooltip("Tempo de recarga da camuflagem (segundos).")]
    public float camoCooldown = 6f;

    [Header("Tongue Pull Stats (optional)")]
    [Tooltip("Alcance da língua/puxão (raycast frontal).")]
    public float tongueRange = 4f;

    [Tooltip("Velocidade com que objectos leves são puxados para o player.")]
    public float tonguePullSpeed = 10f;

    [Header("Sonar Stats (optional)")]
    [Tooltip("Raio do pulso de sonar (revela SonarRevealable).")]
    public float sonarRadius = 6f;

    [Tooltip("Tempo (segundos) que os objectos revelados ficam visíveis.")]
    public float sonarRevealDuration = 4f;

    [Tooltip("Tempo de recarga do sonar (segundos).")]
    public float sonarCooldown = 5f;

    [Header("Night Vision Stats (P8 — Coruja H2, hasVision)")]
    [Tooltip("Raio de detecção de NightVisionRevealable enquanto a visão nocturna está activa (toggle, sem cooldown/duração).")]
    public float nightVisionRadius = 6f;

    [Header("Egg Stats (optional)")]
    [Tooltip("Prefab do ovo (com EggObject + Carryable + ObjectWeight). Botado atrás do player; pesado, dá dano ao cair e pode ser carregado/atirado por formas com canGrab/canThrow.")]
    public GameObject eggPrefab;

    [Tooltip("Tempo de recarga entre ovos (segundos).")]
    public float eggCooldown = 3f;

    [Header("Pounce Stats (Tarefa #7 — Onça)")]
    [Tooltip("Raio de detecção do inimigo mais próximo para o salto ofensivo (Onça).")]
    public float pounceRange = 5f;

    [Tooltip("Velocidade do salto ofensivo (m/s) na direcção do alvo detectado (ou da direcção do player, se nenhum inimigo estiver no alcance).")]
    public float pounceSpeed = 14f;

    [Tooltip("Duração do salto ofensivo (segundos).")]
    public float pounceDuration = 0.35f;

    [Tooltip("Tempo de recarga (segundos) entre saltos ofensivos.")]
    public float pounceCooldown = 1.5f;

    [Header("Spin Attack Stats (Tarefa #7 — Diabo-da-Tasmânia)")]
    [Tooltip("Dano de cada acerto do rodopio ofensivo (independente de attackDamage).")]
    [Range(1, 10)] public int spinAttackDamage = 2;

    [Tooltip("Raio (m) à volta do player atingido pelo rodopio.")]
    public float spinAttackRadius = 1.3f;

    [Tooltip("Duração total do rodopio (segundos).")]
    public float spinAttackDuration = 0.8f;

    [Tooltip("Intervalo (segundos) entre cada 'tick' de dano enquanto o rodopio decorre.")]
    public float spinAttackTickInterval = 0.2f;

    [Tooltip("Força de knockback aplicada a cada tick do rodopio.")]
    public float spinAttackKnockback = 4f;

    [Tooltip("Tempo de recarga (segundos) entre rodopios.")]
    public float spinAttackCooldown = 1.5f;

    [Header("Ice Brake Stats (Tarefa #7 — Pinguim)")]
    [Tooltip("Velocidade horizontal (m/s) removida de cada vez que o botão de Habilidade é premido em cima do gelo (PlayerMotor2D.IsOnIce) — dá controlo de curvas/travagem que o iceSlideFactor normal não permite.")]
    public float iceBrakeStrength = 6f;

    [Header("Animation")]
    public AnimatorOverrideController overrideController;

    [Header("Bestiário — Árvore das Transformações (Tarefa #9)")]
    [Tooltip("Mundo onde este animal é libertado (\"Libertada em\") — também define em que ramo da árvore das transformações este animal aparece.")]
    public WorldData originWorld;

    [Tooltip("Descrição curta da habilidade natural (botão de Habilidade), ex: \"Dash curto\".")]
    public string naturalAbilityText;

    [Tooltip("Descrição do instinto/traço passivo, ex: \"Passos silenciosos e menor detecção\".")]
    [TextArea]
    public string instinctText;

    [Tooltip("Para que situações esta forma é boa, ex: \"Portas temporizadas, rotas baixas e patrulhas\".")]
    [TextArea]
    public string goodForText;

    [Tooltip("Principal limitação desta forma, ex: \"Pouco peso e baixa resistência\".")]
    [TextArea]
    public string weaknessText;

    [Tooltip("Silhueta usada na árvore das transformações antes deste animal ser libertado (animais não-secretos).")]
    public Sprite silhouette;

    [Tooltip("Constelação/gravação/espírito luminoso usado na árvore das transformações depois de libertado. Vazio = usa 'icon'.")]
    public Sprite constellationIcon;

    [Tooltip("Controlador de animação 'idle' mostrado ao lado da ficha na secção Formas (ex: dormir, olhar em redor, brincar com a cauda).")]
    public RuntimeAnimatorController menuIdleController;

    [Tooltip("Animal secreto (GDD: ex. Leão/Wombat/Tigre). Não aparece como ramo/silhueta na árvore enquanto não for libertado — só passa a existir depois de desbloqueado.")]
    public bool isSecretForm = false;

    /// <summary>
    /// Validação em Editor: detecta combinações inválidas de flags de água que
    /// causariam dois sistemas de afogamento em paralelo (OxygenSystem +
    /// WaterMotor2D) ou configurações contraditórias.
    /// </summary>
    private void OnValidate()
    {
        // canDiveAsLand + (swimType==None && !floatsOnWaterSurface) é inválido:
        // OxygenSystem E WaterMotor2D tentariam matar o player em simultâneo.
        if (canDiveAsLand && swimType == SwimType.None && !floatsOnWaterSurface)
        {
            Debug.LogWarning(
                $"[AnimalFormData] '{formId}': canDiveAsLand=true mas swimType==None e " +
                $"floatsOnWaterSurface=false. Estes flags são mutuamente exclusivos — " +
                $"OxygenSystem e WaterMotor2D disparariam afogamento em simultâneo. " +
                $"Define floatsOnWaterSurface=true OU swimType!=None OU desativa canDiveAsLand.",
                this);
        }

        // canDiveAsLand não faz sentido em formas aquáticas nativas (swimType != None).
        if (canDiveAsLand && swimType != SwimType.None)
        {
            Debug.LogWarning(
                $"[AnimalFormData] '{formId}': canDiveAsLand=true numa forma aquática " +
                $"(swimType={swimType}). OxygenSystem ignora formas aquáticas, pelo que " +
                $"este flag não tem efeito. Considera removê-lo para evitar confusão.",
                this);
        }
    }

    /// <summary>
    /// Aplica a Defesa da ficha (1-10) ao dano recebido, por patamares (P1):
    /// 1-4 = sem redução; 5-7 = reduz 1 em ataques de 2+; 8-10 = reduz 1 sempre
    /// (mínimo 1). Nunca zera o dano.
    /// </summary>
    public int ApplyDefense(int damage)
    {
        if (damage <= 0) return 0;

        if (defense >= 8) return Mathf.Max(1, damage - 1);
        if (defense >= 5) return damage >= 2 ? damage - 1 : damage;
        return damage;
    }

    /// <summary>
    /// Como <see cref="ApplyDefense(int)"/>, mas usando "defense + bonusDefense"
    /// (limitado a 10) — usado pelo RollAbility (Pangolim) para aplicar
    /// 'rollDefenseBonus' enquanto a rolar.
    /// </summary>
    public int ApplyDefense(int damage, int bonusDefense)
    {
        if (damage <= 0) return 0;

        int effectiveDefense = Mathf.Min(10, defense + Mathf.Max(0, bonusDefense));

        if (effectiveDefense >= 8) return Mathf.Max(1, damage - 1);
        if (effectiveDefense >= 5) return damage >= 2 ? damage - 1 : damage;
        return damage;
    }
}
